function cn(...classes: (string | false | null | undefined)[]) {
  return classes.filter(Boolean).join(" ");
}

const stateClass: Record<"default" | "half" | "active", string> = {
  default: "opacity-45",
  half: "opacity-70",
  active: "opacity-100",
};

function Block({
  x,
  y,
  state = "default",
  children,
}: {
  x: number;
  y: number;
  state?: "default" | "half" | "active";
  children: React.ReactNode;
}) {
  return (
    <div
      className={cn(
        "absolute z-10 flex justify-center items-center w-[63px] h-[63px] rounded-[14px] cursor-pointer transition-all duration-1000 bg-white shadow-[0_0_0_1px_rgba(9,9,11,0.05),0_1px_2px_rgba(9,9,11,0.05)]",
        stateClass[state],
      )}
      style={{
        left: `calc(-106px + 64px * ${x})`,
        bottom: `calc(-140px + 64px * ${y})`,
      }}
    >
      <div className="w-[53px] h-[53px] flex justify-center items-center rounded-[11px] relative z-10">
        {children}
      </div>
    </div>
  );
}

